    def enable_rate_limiting(
        self,
        service_name: str,
        minute: Optional[int] = None,
        hour: Optional[int] = None,
        day: Optional[int] = None,
        second: Optional[int] = None,
        policy: str = 'local',
        fault_tolerant: bool = True,
        hide_client_headers: bool = False,
    ) -> dict:
        """
        Enable rate limiting plugin on a service.

        SECURITY: Rate limiting must be explicitly configured to prevent abuse.
        At least one rate limit window must be specified.
        """
        service_name = validate_name(service_name, "service name")

        if policy not in ('local', 'cluster', 'redis'):
            raise InputValidationError("Rate limiting policy must be one of: local, cluster, redis")

        config = {
            'policy': policy,
            'fault_tolerant': bool(fault_tolerant),
            'hide_client_headers': bool(hide_client_headers),
        }

        limits_set = False
        if second is not None:
            config['second'] = validate_positive_int(second, "rate limit second", max_val=1000000)
            limits_set = True
        if minute is not None:
            config['minute'] = validate_positive_int(minute, "rate limit minute", max_val=10000000)
            limits_set = True
        if hour is not None:
            config['hour'] = validate_positive_int(hour, "rate limit hour", max_val=100000000)
            limits_set = True
        if day is not None:
            config['day'] = validate_positive_int(day, "rate limit day", max_val=1000000000)
            limits_set = True

        if not limits_set:
            raise InputValidationError(
                "At least one rate limit window (second, minute, hour, day) must be specified. "
                "Rate limiting must not be disabled."
            )

        payload = {
            'name': 'rate-limiting',
            'config': config,
        }

        logger.info("Enabling rate limiting on service: %s", service_name)
        result = self._request('POST', f'/services/{service_name}/plugins', payload)
        logger.info("Rate limiting enabled on service: %s (plugin_id=%s)", service_name, result.get('id'))
        return result

